// getDecodedReader handles character encoding conversion to UTF-8
func getDecodedReader(res *fasthttp.Response, body []byte) (io.Reader, error) {
	contentType := string(res.Header.Peek("Content-Type"))
	mediaType, params, err := mime.ParseMediaType(contentType)
	if err != nil {
		// Default to UTF-8 if we can't parse content type
		return bytes.NewReader(body), nil
	}

	// Only process HTML content
	if mediaType != "text/html" {
		return bytes.NewReader(body), nil
	}

	charset := params["charset"]
	if charset == "" {
		// Default to UTF-8 if no charset specified
		return bytes.NewReader(body), nil
	}

	// Get the encoder for the specified charset
	var enc encoding.Encoding
	switch strings.ToLower(charset) {
	case "iso-8859-1":
		enc = charmap.ISO8859_1
	case "windows-1252":
		enc = charmap.Windows1252
	default:
		var err error
		enc, err = htmlindex.Get(charset)
		if err != nil {
			// Fallback to UTF-8 if charset is unknown
			return bytes.NewReader(body), nil
		}
	}

	// Return a reader that decodes to UTF-8
	return transform.NewReader(bytes.NewReader(body), enc.NewDecoder()), nil
}

// parseHTMLPreview extracts title and meta description from HTML content
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("html parsing failed: %w", err)
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		switch {
		// Extract title from <title> tag
		case n.Type == html.ElementNode && strings.EqualFold(n.Data, "title"):
			if title == "" { // Only take first title tag
				var titleBuilder strings.Builder
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						titleBuilder.WriteString(c.Data)
					}
				}
				title = strings.TrimSpace(titleBuilder.String())
			}

		// Extract description from meta tags
		case n.Type == html.ElementNode && strings.EqualFold(n.Data, "meta"):
			var name, property, content string
			for _, attr := range n.Attr {
				key := strings.ToLower(attr.Key)
				switch key {
				case "name":
					name = strings.ToLower(attr.Val)
				case "property":
					property = strings.ToLower(attr.Val)
				case "content":
					content = attr.Val
				}
			}

			// Prioritize standard meta description
			if name == "description" && content != "" && description == "" {
				description = strings.TrimSpace(content)
			}

			// Fallback to Open Graph description if standard not found
			if property == "og:description" && content != "" && description == "" {
				description = strings.TrimSpace(content)
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

