// validateURL checks if the URL is allowed (valid scheme, non-restricted host)
func validateURL(u *url.URL) error {
	// Validate scheme
	if u.Scheme != "http" && u.Scheme != "https" {
		return fmt.Errorf("invalid scheme")
	}

	// Validate host is not restricted
	if isRestrictedHost(u.Hostname()) {
		return fmt.Errorf("restricted host")
	}

	return nil
}

// isRestrictedHost checks if the host is a restricted address (localhost, private IP, etc.)
func isRestrictedHost(host string) bool {
	// Check common localhost names
	localhostNames := map[string]bool{
		"localhost":            true,
		"localhost.localdomain": true,
		"local":                true,
		"0.0.0.0":              true,
		"::1":                  true,
		"127.0.0.1":            true,
	}
	if localhostNames[strings.ToLower(host)] {
		return true
	}

	// Resolve host to IPs with timeout
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	addrs, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err != nil {
		// Block if resolution fails to avoid potential SSRF
		return true
	}

	// Check each resolved IP
	for _, addr := range addrs {
		ip, ok := netip.AddrFromSlice(addr)
		if !ok {
			continue
		}
		if isRestrictedIP(ip) {
			return true
		}
	}

	return false
}

// isRestrictedIP checks if the IP is in a restricted range
func isRestrictedIP(ip netip.Addr) bool {
	// Check loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Check private IP ranges (RFC 1918 and IPv6 unique local)
	privateRanges := []netip.Prefix{
		netip.MustParsePrefix("10.0.0.0/8"),
		netip.MustParsePrefix("172.16.0.0/12"),
		netip.MustParsePrefix("192.168.0.0/16"),
		netip.MustParsePrefix("fc00::/7"),
	}
	for _, r := range privateRanges {
		if r.Contains(ip) {
			return true
		}
	}

	// Check link-local addresses
	if ip.IsLinkLocalUnicast() {
		return true
	}

	// Check multicast and unspecified addresses
	if ip.IsMulticast() || ip.IsUnspecified() {
		return true
	}

	return false
}

