package main

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"html"
	htmltok "golang.org/x/net/html"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// IsAllowedHost checks if a given host is allowed (not internal/private/loopback)
func IsAllowedHost(ctx context.Context, host string) (bool, error) {
	// Split port from host if present
	hostWithoutPort, _, err := net.SplitHostPort(host)
	if err != nil {
		// No port found, use original host
		hostWithoutPort = host
	}

	// Resolve host to IP addresses with context timeout
	resolver := net.Resolver{}
	ips, err := resolver.LookupIP(ctx, "ip", hostWithoutPort)
	if err != nil {
		return false, fmt.Errorf("failed to resolve host: %w", err)
	}

	for _, ip := range ips {
		// Block loopback addresses
		if ip.IsLoopback() {
			return false, fmt.Errorf("access to loopback addresses is forbidden")
		}
		// Block private IP addresses
		if ip.IsPrivate() {
			return false, fmt.Errorf("access to private addresses is forbidden")
		}
		// Block link-local addresses
		if ip.IsLinkLocalUnicast() {
			return false, fmt.Errorf("access to link-local addresses is forbidden")
		}
	}

	return true, nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Check if target host is allowed
	allowed, err := IsAllowedHost(ctx.Context(), parsedURL.Host)
	if err != nil {
		ctx.Error(fmt.Sprintf("Host validation failed: %v", err), fasthttp.StatusBadRequest)
		return
	}
	if !allowed {
		ctx.Error("Access to restricted hosts is forbidden", fasthttp.StatusForbidden)
