		ctx.Error(fmt.Sprintf("Failed to serialize response: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(jsonResp)
