func extractPreview(htmlBody []byte) (string, string, error) {
	doc, err := html.Parse(bytes.NewReader(htmlBody))
	if err != nil {
		return "", "", err
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract title tag content
		if n.Type == html.ElementNode && n.Data == "title" {
			var titleText strings.Builder
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				if c.Type == html.TextNode {
					titleText.WriteString(c.Data)
				}
			}
			title = strings.TrimSpace(titleText.String())
		}

		// Extract meta description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				key := strings.ToLower(attr.Key)
				if key == "name" {
					nameAttr = strings.ToLower(attr.Val)
				} else if key == "content" {
					contentAttr = attr.Val
				}
			}
			if nameAttr == "description" {
				description = strings.TrimSpace(contentAttr)
			}
		}

		// Recurse into child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

func main() {
	// Custom request router since fasthttp doesn't have built-in ServeMux
	handler := func(ctx *fasthttp.RequestCtx) {
		path := string(ctx.Path())
		method := string(ctx.Method())

		if path == "/fetch-preview" && method == fasthttp.MethodPost {
			FetchURLPreview(ctx)
			return
		}

		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}

	log.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

