// Handles HTML entity unescaping and whitespace trimming.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := htmltok.NewTokenizer(r)
	inTitle := false
	titleBuf := &strings.Builder{}
	descriptionFound := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case htmltok.ErrorToken:
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil // End of input is not an error
			}
			// Clean up and return results
			cleanTitle := html.UnescapeString(strings.TrimSpace(titleBuf.String()))
			cleanDesc := html.UnescapeString(strings.TrimSpace(description))
			return cleanTitle, cleanDesc, err

		case htmltok.StartTagToken, htmltok.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tag := strings.ToLower(string(tagName))

			if tag == "title" && tokenType == htmltok.StartTagToken {
				inTitle = true
			} else if tag == "meta" && hasAttr {
				var nameVal, contentVal []byte
				foundName := false
				foundContent := false

				// Iterate through meta tag attributes
				for {
					attrKey, attrValue, moreAttr := tokenizer.TagAttr()
					key := strings.ToLower(string(attrKey))

					if key == "name" {
						nameVal = attrValue
						foundName = true
					} else if key == "content" {
						contentVal = attrValue
						foundContent = true
					}

					if !moreAttr {
						break
					}
				}

				// Check if this is a description meta tag
				if foundName && foundContent && strings.ToLower(string(nameVal)) == "description" {
					description = string(contentVal)
					descriptionFound = true

					// Early exit if we have both title and description
					if titleBuf.Len() > 0 {
						cleanTitle := html.UnescapeString(strings.TrimSpace(titleBuf.String()))
						cleanDesc := html.UnescapeString(strings.TrimSpace(description))
						return cleanTitle, cleanDesc, nil
					}
				}
			} else if tag == "title" && tokenType == htmltok.EndTagToken {
				inTitle = false
			}

		case htmltok.TextToken:
			if inTitle {
				titleBuf.Write(tokenizer.Text())
			}
		}

		// Early exit if we have both required fields
		if titleBuf.Len() > 0 && descriptionFound {
			cleanTitle := html.UnescapeString(strings.TrimSpace(titleBuf.String()))
			cleanDesc := html.UnescapeString(strings.TrimSpace(description))
			return cleanTitle, cleanDesc, nil
		}
	}
