// parseHTMLPreview extracts title and meta description from HTML using efficient tokenization.
// It prioritizes standard meta description, falls back to og:description if available.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := htmlx.NewTokenizer(r)
	inTitle := false
	foundTitle := false
	foundDescription := false

	for {
		tt := z.Next()
		switch tt {
		case htmlx.ErrorToken:
			err = z.Err()
			if err == io.EOF {
				err = nil // End of input is not an error
			}
			// Trim whitespace before returning
			title = strings.TrimSpace(title)
			description = strings.TrimSpace(description)
			return
		case htmlx.StartTagToken:
			tn, hasAttr := z.TagName()
			tagName := strings.ToLower(string(tn))

			if tagName == "title" && !foundTitle {
				inTitle = true
			} else if tagName == "meta" && !foundDescription {
				var name, property, content []byte
				for hasAttr {
					key, val, more := z.TagAttr()
					k := strings.ToLower(string(key))
					switch k {
					case "name":
						name = val
					case "property":
						property = val
					case "content":
						content = val
					}
					hasAttr = more
				}

				// Check for standard description first, then OpenGraph description
				if (strings.EqualFold(string(name), "description") || strings.EqualFold(string(property), "og:description")) && len(content) > 0 {
					description = string(content)
					foundDescription = true
				}
			}
		case htmlx.EndTagToken:
			tn, _ := z.TagName()
			tagName := strings.ToLower(string(tn))
			if tagName == "title" {
				inTitle = false
				foundTitle = true
			}
		case htmlx.TextToken:
			if inTitle && !foundTitle {
				// Decode HTML entities (e.g., &amp; to &)
				text := html.UnescapeString(string(z.Text()))
				title += text
			}
		}

		// Early exit if we've found both required fields
		if foundTitle && foundDescription {
			title = strings.TrimSpace(title)
			description = strings.TrimSpace(description)
			return
		}
	}
}

