		resp := PreviewResponse{Error: fmt.Sprintf("Invalid URL: %v", err)}
		ctx.SetContentType("application/json; charset=utf-8")
		ctx.SetStatusCode(fasthttp.StatusForbidden)
		json.NewEncoder(ctx).Encode(resp)
		return
	}

