		resp := PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		ctx.SetContentType("application/json; charset=utf-8")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(resp)
		return
	}

