		resp := PreviewResponse{Error: fmt.Sprintf("Failed to parse content: %v", err)}
		ctx.SetContentType("application/json; charset=utf-8")
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(resp)
		return
	}

	// Return successful response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML content.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false
	foundMetaDescription := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			err := tokenizer.Err()
			if err == io.EOF {
				err = nil
			}
			return title, description, err

		case html.StartTagToken:
			token := tokenizer.Token()
			switch strings.ToLower(token.Data) {
			case "title":
				inTitle = true
			case "meta":
				var name, content string
				var property string
				for _, attr := range token.Attr {
					key := strings.ToLower(attr.Key)
					switch key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = strings.TrimSpace(attr.Val)
					case "property":
						property = strings.ToLower(attr.Val)
					}
				}

				if !foundMetaDescription && name == "description" && content != "" {
					description = content
					foundMetaDescription = true
				} else if !foundMetaDescription && property == "og:description" && content != "" {
					description = content
					foundMetaDescription = true
				}

				// Early exit if we have both title and description
				if title != "" && foundMetaDescription {
					return title, description, nil
				}
			}

		case html.EndTagToken:
			token := tokenizer.Token()
			if strings.ToLower(token.Data) == "title" {
				inTitle = false
			}

		case html.TextToken:
			if inTitle && title == "" {
				title = strings.TrimSpace(tokenizer.Token().Data)
				inTitle = false
				// Early exit if we have title and already found description
				if foundMetaDescription {
					return title, description, nil
				}
			}
		}
	}
}

