		if (ip[0]&0xff) == 0xfe && (ip[1]&0xc0) == 0x80 { // fe80::/10
			return false
		}
	}

	// Allowed if not in any blocked range
	return true
}

// ssrfSafeDial creates a dialer that blocks access to internal IP ranges
func ssrfSafeDial(addr string) (net.Conn, error) {
	dialer := &net.Dialer{
		DualStack: true,
		Timeout:   10 * time.Second,
	}

	dialer.Control = func(network, address string, c syscall.RawConn) error {
		host, _, err := net.SplitHostPort(address)
		if err != nil {
			return fmt.Errorf("failed to split address: %w", err)
		}

		ip := net.ParseIP(host)
		if ip == nil {
			return fmt.Errorf("invalid IP address: %s", host)
		}

		if !isIPAllowed(ip) {
			return fmt.Errorf("access to internal IP %s is blocked", ip.String())
		}

		return nil
	}

	// Use TCP network since we're dealing with HTTP/HTTPS
	return dialer.Dial("tcp", addr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		sendJSONError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Validate Content-Type is JSON
	contentType := string(ctx.Request.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "application/json") {
		sendJSONError(ctx, "Content-Type must be application/json", fasthttp.StatusBadRequest)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		sendJSONError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and format
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendJSONError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendJSONError(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Initialize fasthttp client with SSRF protection and timeouts
	client := &fasthttp.Client{
		Dial:                ssrfSafeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	const maxRedirects = 10
	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Check for successful status code (2xx range)
	if res.StatusCode() < fasthttp.StatusOK || res.StatusCode() >= fasthttp.StatusMultipleChoices {
		sendJSONError(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		sendJSONError(ctx, "Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Send successful response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		sendJSONError(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// parseHTMLPreview extracts title and meta description from HTML content
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Extract title tag content
	var traverseTitle func(*html.Node)
	traverseTitle = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverseTitle(c)
		}
	}
	traverseTitle(doc)

	// Extract meta description (fall back to Open Graph description if available)
	var traverseMeta func(*html.Node)
	traverseMeta = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var (
				name     string
				property string
				content  string
			)

			for _, attr := range n.Attr {
				switch strings.ToLower(attr.Key) {
				case "name":
					name = strings.ToLower(attr.Val)
				case "property":
					property = strings.ToLower(attr.Val)
				case "content":
					content = strings.TrimSpace(attr.Val)
				}
			}

			// Prefer standard meta description first
			if name == "description" && content != "" && description == "" {
				description = content
			}
			// Fall back to Open Graph description if standard is missing
			if property == "og:description" && content != "" && description == "" {
				description = content
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverseMeta(c)
		}
	}
	traverseMeta(doc)

	return title, description, nil
}

// sendJSONError sends a standardized JSON error response
func sendJSONError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	resp := PreviewResponse{Error: message}
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(statusCode)

	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		// Fall back to plain text if JSON encoding fails
		ctx.Error("Failed to encode error response", fasthttp.StatusInternalServerError)
	}
}

