// validateHost checks if the host resolves to a non-private IP
func validateHost(host string) error {
	// Extract hostname without port
	hostWithoutPort := host
	if strings.Contains(host, ":") {
		var err error
		hostWithoutPort, _, err = net.SplitHostPort(host)
		if err != nil {
			return fmt.Errorf("invalid hostname format: %v", err)
		}
	}

	// Resolve hostname to IPs
	ips, err := net.LookupIP(hostWithoutPort)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	// Check each IP for private ranges
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP ranges is not allowed")
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is in a private or restricted range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return true
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return true
		case ip4[0] == 192 && ip4[1] == 168:
			return true
		default:
			return false
		}
	}

	// Check IPv6 private ranges
	if ip6 := ip.To16(); ip6 != nil {
		// Unique Local Address (ULA): fc00::/7
		if (ip6[0] & 0xfe) == 0xfc {
			return true
		}
		// Link-local address: fe80::/10
		if (ip6[0] & 0xff) == 0xfe && (ip6[1] & 0xc0) == 0x80 {
			return true
		}
	}

	return false
}

// isRedirectStatusCode checks if the status code indicates a redirect
func isRedirectStatusCode(code int) bool {
	switch code {
	case fasthttp.StatusMovedPermanently,
		fasthttp.StatusFound,
		fasthttp.StatusSeeOther,
		fasthttp.StatusTemporaryRedirect,
		fasthttp.StatusPermanentRedirect:
		return true
	default:
		return false
	}
}

// parseHTMLPreview extracts title and meta description from HTML content
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Extract title tag content
	var extractTitle func(*html.Node)
	extractTitle = func(n *html.Node) {
		if n.Type == html.ElementNode && n.DataAtom == atom.Title {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractTitle(c)
		}
	}
	extractTitle(doc)

	// Extract meta description (fallback to Open Graph if available)
	var extractDescription func(*html.Node)
	extractDescription = func(n *html.Node) {
		if n.Type == html.ElementNode && n.DataAtom == atom.Meta {
			var metaName, metaContent, ogProperty string
			for _, attr := range n.Attr {
				switch {
				case attr.Key == "name":
					metaName = strings.ToLower(attr.Val)
				case attr.Key == "content":
					metaContent = strings.TrimSpace(attr.Val)
				case attr.Key == "property":
					ogProperty = strings.ToLower(attr.Val)
				}
			}

			if metaName == "description" && metaContent != "" {
				description = metaContent
			} else if ogProperty == "og:description" && metaContent != "" && description == "" {
				description = metaContent
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractDescription(c)
		}
	}
	extractDescription(doc)

	return title, description, nil
}

// sendJSONResponse sends a JSON response to the client
func sendJSONResponse(ctx *fasthttp.RequestCtx, resp PreviewResponse) {
	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

