		json.NewEncoder(ctx).Encode(map[string]string{"error": "Missing required 'url' field"})
		return
	}

	// Initialize fasthttp client with required configuration
	client := &fasthttp.Client{
		DialTimeout: func(addr string, _ time.Duration) (net.Conn, error) {
			return fasthttp.DialDualStackTimeout(addr, 5*time.Second)
		},
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
	}

	// Prepare request for target URL
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

