	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Failed to fetch URL: " + err.Error()})
		return
	}

