	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(map[string]string{"error": fmt.Sprintf("URL returned status code %d: %s", resp.StatusCode(), fasthttp.StatusMessage(resp.StatusCode()))})
		return
	}

	// Parse HTML content to extract title and description
	title, description := parseHTML(resp.Body())

	// Prepare and send response
	preview := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(preview); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Failed to encode response: " + err.Error()})
	}
}

func parseHTML(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
