	description = strings.TrimSpace(description)

	return title, description, nil
}

// extractAttributes converts HTML tag attributes into a map with lowercase keys
func extractAttributes(hasAttr bool, tr *tokenizer.Tokenizer) map[string]string {
	attrs := make(map[string]string)
	for hasAttr {
		key, val, moreAttr := tr.TagAttr()
		keyStr := strings.ToLower(string(key))
		valStr := html.UnescapeString(string(val))
		attrs[keyStr] = strings.TrimSpace(valStr)
		hasAttr = moreAttr
	}
	return attrs
}

// updateDescription sets the description from meta tags, preferring standard description over Open Graph
func updateDescription(description *string, attrs map[string]string) {
	if *description != "" {
		return // Already found a description
	}

	// Check standard meta description first
	if attrs["name"] == "description" {
		*description = attrs["content"]
		return
	}

	// Fallback to Open Graph description
	if attrs["property"] == "og:description" {
		*description = attrs["content"]
	}
}

