	// Parse incoming JSON payload
	var payload requestPayload
	if err := json.Unmarshal(ctx.PostBody(), &payload); err != nil {
		ctx.Error(fmt.Sprintf("Invalid JSON body: %v", err), fasthttp.StatusBadRequest)
		return
	}

	// Validate URL presence and format
	if payload.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.Parse(payload.URL)
	if err != nil || !parsedURL.IsAbs() {
		ctx.Error("Valid absolute URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Prepare HTTP request to fetch the target URL
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.Header.SetMethod(fasthttp.MethodGet)

	var uri fasthttp.URI
	if err := uri.Parse(nil, []byte(payload.URL)); err != nil {
		ctx.Error("Failed to process URL", fasthttp.StatusBadRequest)
		return
	}
	req.SetURI(&uri)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Execute request with redirect following
	if err := httpClient.Do(req, resp); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Extract title and description from HTML content
	title, description := extractPreview(resp.Body())

	// Prepare and send response
	response := previewResponse{
		Title:       title,
		Description: description,
	}

	respBytes, err := json.Marshal(response)
	if err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.Response.Header.SetContentType("application/json")
	ctx.Response.SetStatusCode(fasthttp.StatusOK)
	ctx.Response.SetBody(respBytes)
}

func extractPreview(htmlBytes []byte) (string, string) {
	var title strings.Builder
	var description string
	inTitle := false

	tokenizer := html.NewTokenizer(bytes.NewReader(htmlBytes))

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// End of document or parsing error, return collected data
			return strings.TrimSpace(title.String()), strings.TrimSpace(description)
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := strings.ToLower(token.Data)

			if tagName == "title" {
				inTitle = true
			} else if tagName == "meta" {
				var metaName, metaContent string
				for _, attr := range token.Attr {
					key := strings.ToLower(attr.Key)
					switch key {
					case "name":
						metaName = strings.ToLower(attr.Val)
					case "content":
						metaContent = attr.Val
					}
				}
				if metaName == "description" && metaContent != "" {
					description = metaContent
				}
			}
		case html.EndTagToken:
			token := tokenizer.Token()
			if strings.ToLower(token.Data) == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle {
				title.WriteString(tokenizer.Token().Data)
			}
		}
	}
}

