			extractTitle(c)
		}
	}
	extractTitle(doc)

	// Extract meta description tag content
	var extractMetaDesc func(*html.Node)
	extractMetaDesc = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				switch strings.ToLower(attr.Key) {
				case "name":
