// parseHTMLPreview extracts title and meta description from HTML content
func parseHTMLPreview(r *bytes.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Traverse HTML to find title and meta description
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop if we've found both values
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if title == "" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				if description != "" {
					return
				}
				var metaName, metaContent string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						metaName = strings.ToLower(attr.Val)
					case "content":
						metaContent = strings.TrimSpace(attr.Val)
					}
				}
				if metaName == "description" && metaContent != "" {
					description = metaContent
				}
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	// Fallback to OpenGraph tags if primary values not found
	if title == "" {
		title = findOpenGraphTag(doc, "title")
	}
	if description == "" {
		description = findOpenGraphTag(doc, "description")
	}

	return title, description, nil
}

// findOpenGraphTag extracts OpenGraph meta tags from HTML document
func findOpenGraphTag(doc *html.Node, tagName string) string {
	var result string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if result != "" {
			return
		}

		if n.Type == html.ElementNode && n.Data == "meta" {
			var property, content string
			for _, attr := range n.Attr {
				switch attr.Key {
				case "property":
					if strings.ToLower(attr.Val) == "og:"+tagName {
						property = attr.Val
					}
				case "content":
					content = strings.TrimSpace(attr.Val)
				}
			}
			if property != "" && content != "" {
				result = content
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)
	return result
}

