// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	currentURL := targetURL
	var fetchErr error
	maxRedirectCounts := 10
	redirectCount := 0

	for {
		freq.Reset()
		freq.SetRequestURI(currentURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		res.Reset()
		if fetchErr = client.Do(freq, res); fetchErr != nil {
			break
		}

		statusCode := res.StatusCode()

		// Check if response is a redirect
		isRedirect := statusCode == fasthttp.StatusMovedPermanently ||
			statusCode == fasthttp.StatusFound ||
			statusCode == fasthttp.StatusSeeOther ||
			statusCode == fasthttp.StatusTemporaryRedirect ||
			statusCode == fasthttp.StatusPermanentRedirect

		if !isRedirect {
			break
		}

		if redirectCount >= maxRedirectCounts {
			fetchErr = fmt.Errorf("too many redirects (max allowed: %d)", maxRedirectCounts)
			break
		}

		// Get and resolve redirect location
		location := res.Header.Peek("Location")
		if len(location) == 0 {
			fetchErr = fmt.Errorf("redirect response missing Location header")
			break
		}

		parsedCurrent, parseErr := url.Parse(currentURL)
		if parseErr != nil {
			fetchErr = parseErr
			break
		}
		parsedLocation, parseErr := url.Parse(string(location))
		if parseErr != nil {
			fetchErr = parseErr
			break
		}
		currentURL = parsedCurrent.ResolveReference(parsedLocation).String()

		redirectCount++
