		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML content.
// It falls back to Open Graph description (og:description) if standard meta description is missing.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	titleFound := false
	descriptionFound := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil // End of document is not an error
			}
			return strings.TrimSpace(title), strings.TrimSpace(description), err

		case html.StartTagToken:
			tagName, _ := tokenizer.TagName()
			tag := strings.ToLower(string(tagName))

			if tag == "title" && !titleFound {
				// Collect all text content inside title tag
				var titleBuilder strings.Builder
				for {
					nextTT := tokenizer.Next()
					switch nextTT {
					case html.TextToken:
						titleBuilder.Write(tokenizer.Text())
					case html.EndTagToken:
						endTag, _ := tokenizer.TagName()
						if strings.ToLower(string(endTag)) == "title" {
							title = titleBuilder.String()
							titleFound = true
							break
						}
					case html.ErrorToken:
						err = tokenizer.Err()
						if err == io.EOF {
							err = nil
						}
						title = titleBuilder.String()
						titleFound = true
						break
					}
					if titleFound || err != nil {
						break
					}
				}
			} else if tag == "meta" && !descriptionFound {
				// Extract meta tag attributes
				var (
					name     string
					property string
					content  string
				)

				hasAttr := true
				for hasAttr {
					key, val, more := tokenizer.TagAttr()
					keyStr := strings.ToLower(string(key))
					valStr := string(val)

					switch keyStr {
					case "name":
						name = strings.ToLower(valStr)
					case "property":
						property = strings.ToLower(valStr)
					case "content":
						content = valStr
					}
					hasAttr = more
				}

				// Check for standard description first, then Open Graph description
				if (name == "description" || property == "og:description") && content != "" {
					description = content
					descriptionFound = true
				}
			}

			// Early exit if both title and description are found
			if titleFound && descriptionFound {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
		}
	}
}

