// isSafeHost checks if a host is not a loopback or private IP address
func isSafeHost(host string, timeout time.Duration) error {
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	hostWithoutPort, _, err := net.SplitHostPort(host)
	if err != nil {
		hostWithoutPort = host // Assume no port specified
	}

	// Check if host is an IP address
	ip := net.ParseIP(hostWithoutPort)
	if ip != nil {
		if ip.IsLoopback() || ip.IsPrivate() {
			return fmt.Errorf("loopback or private IP address")
		}
		return nil
	}

	// Resolve hostname to IP addresses with timeout
	resolver := &net.Resolver{}
	ips, err := resolver.LookupIP(ctx, "ip", hostWithoutPort)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %w", err)
	}

	// Check each resolved IP
	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() {
			return fmt.Errorf("host resolves to loopback or private IP")
		}
	}

	return nil
}

// parseHTMLPreview extracts title and meta description from HTML using safe parser
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		switch {
		case n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil:
			title = strings.TrimSpace(n.FirstChild.Data)
		case n.Type == html.ElementNode && n.Data == "meta":
			var name, content string
			for _, attr := range n.Attr {
				switch strings.ToLower(attr.Key) {
				case "name":
					if strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
				case "content":
					content = attr.Val
				}
			}
			if name != "" && content != "" {
				description = strings.TrimSpace(content)
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

