		if targetURL == "" {
			sendErrorResponse(ctx, "URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Validate URL format and scheme
		parsedURL, err := url.ParseRequestURI(targetURL)
		if err != nil {
			sendErrorResponse(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
			return
		}

		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			sendErrorResponse(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
			return
		}

		// Extract host without port
		host := parsedURL.Host
		if _, _, err := net.SplitHostPort(host); err == nil {
			var splitErr error
			host, _, splitErr = net.SplitHostPort(host)
			if splitErr != nil {
				sendErrorResponse(ctx, "Invalid host format", fasthttp.StatusBadRequest)
				return
			}
		}

		// Resolve host to IP addresses
		ips, err := net.LookupIP(host)
		if err != nil {
			sendErrorResponse(ctx, fmt.Sprintf("Failed to resolve host: %v", err), fasthttp.StatusBadGateway)
			return
		}

		// Block access to private, loopback, or link-local addresses
		for _, ip := range ips {
			if isRestrictedIP(ip) {
				sendErrorResponse(ctx, "Access to internal addresses is prohibited", fasthttp.StatusForbidden)
				return
			}
		}

		// Use fasthttp.Client to fetch with timeout
		client := &fasthttp.Client{
			Dial:                fasthttp.DialDualStack,
			ReadTimeout:         10 * time.Second,
			WriteTimeout:        10 * time.Second,
			MaxIdleConnDuration: 10 * time.Second,
			MaxConnsPerHost:     10,
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		maxRedirectCounts := 10
		if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
			sendErrorResponse(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		// Check for successful status code (2xx range)
		if res.StatusCode() < fasthttp.StatusOK || res.StatusCode() >= fasthttp.StatusMultipleChoices {
			sendErrorResponse(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
			return
		}

		bodyBytes := res.Body()
		if len(bodyBytes) == 0 {
			sendErrorResponse(ctx, "Empty response body", fasthttp.StatusBadGateway)
			return
		}

		title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
		if err != nil {
			sendErrorResponse(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetStatusCode(fasthttp.StatusOK)
		ctx.Response.Header.SetContentType("application/json; charset=utf-8")
		jsonBytes, err := json.Marshal(resp)
		if err != nil {
			sendErrorResponse(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
		if _, err := ctx.Write(jsonBytes); err != nil {
			sendErrorResponse(ctx, "Failed to write response", fasthttp.StatusInternalServerError)
		}
	} else {
		sendErrorResponse(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// isRestrictedIP checks if an IP address is in a restricted range (loopback, private, link-local)
func isRestrictedIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}

	// Check IPv4 restricted ranges
	if ipv4 := ip.To4(); ipv4 != nil {
		switch {
		case ipv4[0] == 10: // 10.0.0.0/8
			return true
		case ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31: //172.16.0.0/12
			return true
		case ipv4[0] == 192 && ipv4[1] == 168: //192.168.0.0/16
			return true
		case ipv4[0] == 169 && ipv4[1] == 254: //169.254.0.0/16 (link-local)
			return true
		default:
			return false
		}
	}

	// Check IPv6 restricted ranges
	if ipv6 := ip.To16(); ipv6 != nil && len(ipv6) == 16 {
		// Unique Local Addresses (fc00::/7)
		if ipv6[0] == 0xfc || ipv6[0] == 0xfd {
			return true
		}
		// Link-local addresses (fe80::/10)
		if ipv6[0] == 0xfe && (ipv6[1]&0xc0) == 0x80 {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML content using efficient tokenization.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	inTitle := false
	titleFound := false
	descriptionFound := false

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			err = z.Err()
			if err == io.EOF {
				err = nil // End of input is not an error
			}
			return
		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := z.TagName()
			tag := strings.ToLower(string(tagName))

			if tag == "title" && !titleFound {
				inTitle = true
			} else if tag == "meta" && !descriptionFound {
				var name, content string
				for hasAttr {
					key, val, more := z.TagAttr()
					attrKey := strings.ToLower(string(key))
					attrVal := string(val)

					if attrKey == "name" {
						name = strings.ToLower(attrVal)
					} else if attrKey == "content" {
						content = attrVal
					}
					hasAttr = more
				}
				if name == "description" && content != "" {
					description = strings.TrimSpace(content)
					descriptionFound = true
					// Early exit if both fields are found
					if titleFound {
						return
					}
				}
			}
		case html.TextToken:
			if inTitle && !titleFound {
				text := strings.TrimSpace(string(z.Text()))
				if text != "" {
					title = text
					titleFound = true
					inTitle = false
					// Early exit if both fields are found
					if descriptionFound {
						return
					}
				}
			}
		case html.EndTagToken:
			tagName, _ := z.TagName()
			tag := strings.ToLower(string(tagName))
			if tag == "title" {
				inTitle = false
			}
		}
	}
}

// sendErrorResponse sends a standardized JSON error response.
func sendErrorResponse(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	resp := PreviewResponse{Error: message}
	ctx.SetStatusCode(statusCode)
	ctx.Response.Header.SetContentType("application/json; charset=utf-8")
	jsonBytes, err := json.Marshal(resp)
	if err != nil {
		// Fallback to plain text error if JSON encoding fails
		ctx.Response.Header.SetContentType("text/plain; charset=utf-8")
		ctx.Error("Failed to encode error response", fasthttp.StatusInternalServerError)
		return
	}
	if _, err := ctx.Write(jsonBytes); err != nil {
		ctx.Response.Header.SetContentType("text/plain; charset=utf-8")
		ctx.Error("Failed to write response", fasthttp.StatusInternalServerError)
	}
}

