		enc, _ = htmlindex.Get("utf-8")
	}
	decoder := enc.NewDecoder()
	decodedReader := decoder.Reader(r)

	// Parse HTML document
	doc, err := html.Parse(decodedReader)
	if err != nil {
		return "", "", fmt.Errorf("html parsing failed: %v", err)
	}

	// Extract title
	var titleNode *html.Node
	var findTitle func(*html.Node)
	findTitle = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			titleNode = n.FirstChild
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findTitle(c)
		}
	}
	findTitle(doc)
	if titleNode != nil {
		title = strings.TrimSpace(titleNode.Data)
	}

	// Extract meta description
	var findMetaDescription func(*html.Node)
	findMetaDescription = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
